// src/pages/Dashboard.js
import React, { useEffect, useState } from "react";
import api, { listVehicles } from "../services/api";
import VehicleForm from "../components/VehicleForm";
import VehicleTable from "../components/VehicleTable";
import MapComponent from "../components/MapComponent";
import AnalyticsChart from "../components/AnalyticsChart";
import "./dashboard.css";

export default function Dashboard() {
  const [metrics, setMetrics] = useState({
    vehicles: 0,
    activeTrips: 0,
    alerts: 0,
    lastUpdated: null,
  });
  const [refreshKey, setRefreshKey] = useState(0);

  // Load summary metrics once
  useEffect(() => {
    const controller = new AbortController();
    api
      .get("/dashboard", { signal: controller.signal })
      .then((res) => setMetrics(res.data))
      .catch((err) => console.error("Dashboard load error:", err));
    return () => controller.abort();
  }, []);

  // Optional: keep the metric count in sync with current rows
  useEffect(() => {
    let ignore = false;
    async function syncCounts() {
      try {
        const rows = await listVehicles();
        if (!ignore && Array.isArray(rows)) {
          setMetrics((m) => ({ ...m, vehicles: rows.length }));
        }
      } catch (e) {
        // silent; table already shows detailed fetch errors
      }
    }
    syncCounts();
  }, [refreshKey]);

  const refreshVehicles = () => setRefreshKey((k) => k + 1);

  return (
    <div style={{ padding: 16, display: "grid", gap: 16 }}>
      <h2>Dashboard</h2>

      <div style={{ display: "flex", gap: 16 }}>
        <InfoCard label="Vehicles" value={metrics.vehicles} />
        <InfoCard label="Active Trips" value={metrics.activeTrips} />
        <InfoCard label="Alerts" value={metrics.alerts} />
      </div>

      <div style={{ display: "grid", gap: 16, gridTemplateColumns: "1fr 1fr" }}>
        <div style={{ border: "1px solid #eee", borderRadius: 8, padding: 12 }}>
          <h3>Live Vehicles</h3>
          <VehicleTable refreshKey={refreshKey} />
        </div>

        <div style={{ border: "1px solid #eee", borderRadius: 8, padding: 12 }}>
          <h3>Add Vehicle</h3>
          <VehicleForm onCreated={refreshVehicles} />
        </div>
      </div>

      <div style={{ display: "grid", gap: 16, gridTemplateColumns: "1fr 1fr" }}>
        <div style={{ border: "1px solid #eee", borderRadius: 8, padding: 12, minHeight: 360 }}>
          <h3>Map</h3>
          {/* If MapComponent needs vehicle data, switch VehicleTable to lift state up and pass vehicles here */}
          <MapComponent vehicles={[]} />
        </div>

        <div style={{ border: "1px solid #eee", borderRadius: 8, padding: 12, minHeight: 360 }}>
          <h3>Analytics</h3>
          <AnalyticsChart vehicles={[]} />
        </div>
      </div>

      <p style={{ marginTop: 8, color: "#666" }}>
        Last updated: {metrics.lastUpdated ? new Date(metrics.lastUpdated).toLocaleString() : "—"}
      </p>
    </div>
  );
}

function InfoCard({ label, value }) {
  return (
    <div style={{ border: "1px solid #ddd", borderRadius: 8, padding: 12, minWidth: 160 }}>
      <div style={{ fontSize: 12, color: "#666" }}>{label}</div>
      <div style={{ fontSize: 24, fontWeight: 700 }}>{value}</div>
    </div>
  );
}
